SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW vr_dep_no_move (deposit_account_no, last_access_date, last_int_date) AS SELECT 	sc_dep_m_creditor.deposit_account_no
				,( SELECT coalesce( max( sc_dep_m_creditor_item.operate_date  ),null)	
				FROM sc_dep_m_creditor_item
				WHERE  sc_dep_m_creditor_item.deposit_account_no = sc_dep_m_creditor.deposit_account_no    
				AND  refer_to_deposit_doc_no not in ( '#COM#' , 'NB' )   ) as last_access_date

				,( SELECT coalesce( min( sc_dep_m_creditor_item.operate_date  )	, null )
				FROM sc_dep_m_creditor_item  
				WHERE  sc_dep_m_creditor_item.deposit_account_no = sc_dep_m_creditor.deposit_account_no    
				AND  refer_to_deposit_doc_no  in ( '#COM#' , 'NB' )   ) as last_int_date

    FROM sc_dep_m_creditor  
    WHERE 1=1;

